import { initializeApp } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-app.js";
import { getFirestore } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js";
import { getAuth } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js";

// GANTI DENGAN CONFIG ANDA DARI FIREBASE CONSOLE
const firebaseConfig = {
  apiKey: "AIzaSy...", 
  authDomain: "your-project.firebaseapp.com",
  projectId: "your-project",
  storageBucket: "your-project.appspot.com",
  messagingSenderId: "123456789",
  appId: "1:123456789:web:abcdef"
};

const app = initializeApp(firebaseConfig);
export const auth = getAuth(app);
export const firestore = getFirestore(app);

import React, { useState, useEffect } from 'react';
import LandingPage from './views/LandingPage.tsx';
import AdminDashboard from './views/AdminDashboard.tsx';
import StudentDashboard from './views/StudentDashboard.tsx';
import Login from './views/Login.tsx';
import Signup from './views/Signup.tsx';
import { User, Role, SiteSettings, ClassRoom } from './types.ts';
import { Loader2, RefreshCw, CheckCircle, AlertCircle } from 'lucide-react';
import { firestore, auth } from './firebase.ts';
import { 
  collection, 
  doc, 
  getDoc, 
  getDocs, 
  setDoc, 
  updateDoc, 
  deleteDoc, 
  query, 
  where,
  addDoc 
} from "https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js";
import { onAuthStateChanged } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js";

export const db = {
  get: async (key: string) => {
    try {
      const querySnapshot = await getDocs(collection(firestore, key));
      return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
    } catch (err) {
      console.error("Firebase Get Error:", err);
      return [];
    }
  },

  getSingle: async (key: string, id: string) => {
    try {
      const docSnap = await getDoc(doc(firestore, key, id));
      return docSnap.exists() ? { id: docSnap.id, ...docSnap.data() } : null;
    } catch (err) {
      return null;
    }
  },

  saveAll: async (key: string, value: any) => {
    window.dispatchEvent(new CustomEvent('sync-start'));
    try {
      if (Array.isArray(value)) {
        for (const item of value) {
          const id = item.id || Math.random().toString(36).substr(2, 9);
          await setDoc(doc(firestore, key, id), item, { merge: true });
        }
      } else {
        await setDoc(doc(firestore, "settings", key), value, { merge: true });
      }
      window.dispatchEvent(new CustomEvent('sync-end'));
    } catch (err) {
      window.dispatchEvent(new CustomEvent('sync-error'));
    }
  },

  append: async (key: string, value: any) => {
    window.dispatchEvent(new CustomEvent('sync-start'));
    try {
      await addDoc(collection(firestore, key), value);
      window.dispatchEvent(new CustomEvent('sync-end'));
    } catch (err) {
      window.dispatchEvent(new CustomEvent('sync-error'));
    }
  },

  deleteKey: async (key: string) => {
    // Firebase tidak mendukung penghapusan koleksi secara langsung dari client
    // Biasanya kita menghapus dokumen di dalamnya satu per satu
    console.warn("Delete collection is limited on client side");
  }
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'landing' | 'login' | 'signup' | 'dashboard'>('landing');
  const [loginRole, setLoginRole] = useState<Role | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [syncStatus, setSyncStatus] = useState<'idle' | 'syncing' | 'success' | 'error'>('idle');
  const [settings, setSettings] = useState<SiteSettings>({
    logoUrl: 'https://www.alirsyad.or.id/wp-content/uploads/download/alirsyad-alislamiyyah.png',
    heroImageUrl: 'https://cdn.fpt-is.com/vi/he-thong-elearning-1.png',
    siteName: 'Informatika SMP Al Irsyad Surakarta'
  });

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      if (firebaseUser) {
        // Cari profil di Firestore
        const userDoc = await db.getSingle('users', firebaseUser.uid);
        if (userDoc) {
          setUser(userDoc as User);
          setView('dashboard');
        }
      } else {
        setUser(null);
        if (view === 'dashboard') setView('landing');
      }
      setIsLoading(false);
    });

    const fetchSettings = async () => {
      const stored = await getDoc(doc(firestore, "settings", "site_configs"));
      if (stored.exists()) {
        setSettings(stored.data() as SiteSettings);
      }
    };

    fetchSettings();
    return () => unsubscribe();
  }, []);

  useEffect(() => {
    const handleSyncStart = () => setSyncStatus('syncing');
    const handleSyncEnd = () => {
      setSyncStatus('success');
      setTimeout(() => setSyncStatus('idle'), 3000);
    };
    const handleSyncError = () => {
      setSyncStatus('error');
      setTimeout(() => setSyncStatus('idle'), 5000);
    };

    window.addEventListener('sync-start', handleSyncStart);
    window.addEventListener('sync-end', handleSyncEnd);
    window.addEventListener('sync-error', handleSyncError);

    return () => {
      window.removeEventListener('sync-start', handleSyncStart);
      window.removeEventListener('sync-end', handleSyncEnd);
      window.removeEventListener('sync-error', handleSyncError);
    };
  }, []);

  const handleLogin = (u: User) => {
    setUser(u);
    setView('dashboard');
  };

  const handleLogout = async () => {
    await auth.signOut();
    setUser(null);
    setView('landing');
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center">
        <Loader2 className="w-12 h-12 text-emerald-600 animate-spin mb-4" />
        <p className="text-slate-400 font-bold uppercase text-xs tracking-widest">Menghubungkan ke Cloud...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen selection:bg-emerald-100 selection:text-emerald-900 relative">
      <div className={`fixed top-4 right-4 z-[9999] flex items-center gap-2 px-4 py-2 rounded-full shadow-lg border transition-all duration-500 transform ${
        syncStatus === 'idle' ? 'translate-y-[-100px] opacity-0' : 'translate-y-0 opacity-100'
      } ${
        syncStatus === 'syncing' ? 'bg-blue-600 text-white' : 
        syncStatus === 'success' ? 'bg-emerald-600 text-white' : 'bg-red-600 text-white'
      }`}>
        {syncStatus === 'syncing' && <RefreshCw className="animate-spin" size={16} />}
        {syncStatus === 'success' && <CheckCircle size={16} />}
        {syncStatus === 'error' && <AlertCircle size={16} />}
        <span className="text-[10px] font-black uppercase tracking-widest">
          {syncStatus === 'syncing' ? 'Firebase Sync...' : 
           syncStatus === 'success' ? 'Data Cloud Terupdate' : 'Sync Error'}
        </span>
      </div>

      {view === 'landing' && <LandingPage onNavigateLogin={(role) => { setLoginRole(role); setView('login'); }} onNavigateSignup={() => setView('signup')} settings={settings} />}
      {view === 'login' && <Login role={loginRole || 'STUDENT'} onBack={() => setView('landing')} onLogin={handleLogin} onNavigateSignup={() => setView('signup')} />}
      {view === 'signup' && <Signup onBack={() => setView('login')} onSignup={() => { setLoginRole('STUDENT'); setView('login'); }} logoUrl={settings.logoUrl} />}
      {view === 'dashboard' && user && (
        user.role === 'ADMIN' 
          ? <AdminDashboard user={user} onLogout={handleLogout} settings={settings} setSettings={setSettings} onUpdateUser={setUser} /> 
          : <StudentDashboard user={user} onLogout={handleLogout} settings={settings} onUpdateUser={setUser} />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { ArrowLeft, Lock, User as UserIcon, Loader2, Eye, EyeOff, AlertCircle, RefreshCw } from 'lucide-react';
import { Role, User } from '../types';
import { auth, firestore } from '../firebase.ts';
import { signInWithEmailAndPassword } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js";
import { doc, getDoc } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js";

interface LoginProps {
  role: Role;
  onBack: () => void;
  onLogin: (user: User) => void;
  onNavigateSignup: () => void;
}

const Login: React.FC<LoginProps> = ({ role, onBack, onLogin, onNavigateSignup }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    // Karena Firebase Auth butuh email, kita konversi username jadi email sekolah virtual
    const email = `${username.trim().toLowerCase()}@alirsyad.sch.id`;

    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      const firebaseUser = userCredential.user;

      // Ambil data profil dari Firestore
      const userDoc = await getDoc(doc(firestore, "users", firebaseUser.uid));

      if (userDoc.exists()) {
        const userData = userDoc.data() as User;
        if (userData.role !== role) {
          await auth.signOut();
          setError(`Akun ini tidak terdaftar sebagai ${role}.`);
        } else if (userData.status === 'PENDING') {
          await auth.signOut();
          setError("Akun Anda masih menunggu persetujuan Guru.");
        } else {
          onLogin({ ...userData, id: firebaseUser.uid });
        }
      } else {
        setError("Profil pengguna tidak ditemukan di database.");
      }
    } catch (err: any) {
      if (err.code === 'auth/user-not-found') setError("Username tidak ditemukan.");
      else if (err.code === 'auth/wrong-password') setError("Password salah.");
      else setError("Gagal login: " + err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-white">
      <div className="hidden md:flex flex-1 bg-emerald-600 items-center justify-center p-20 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-64 h-64 bg-emerald-500 rounded-full -mr-32 -mt-32 opacity-50"></div>
        <div className="relative z-10 text-white max-w-md">
          <h2 className="text-5xl font-extrabold mb-6">Portal {role === 'ADMIN' ? 'Guru' : 'Siswa'}</h2>
          <p className="text-xl opacity-90">Sistem E-Learning Informatika Berbasis Firebase Cloud.</p>
        </div>
      </div>

      <div className="flex-1 bg-white flex flex-col justify-center items-center px-6 py-12">
        <div className="w-full max-w-md">
          <button onClick={onBack} className="flex items-center gap-2 text-slate-400 hover:text-slate-800 mb-10 font-bold"><ArrowLeft size={18} /> Kembali</button>
          <h3 className="text-4xl font-black text-slate-900 mb-2">Login Cloud</h3>
          <p className="text-slate-500 mb-8">Masukkan kredensial Anda untuk akses sistem.</p>

          {error && (
            <div className="mb-6 p-4 bg-rose-50 border border-rose-100 rounded-2xl flex items-center gap-3 text-rose-600 text-sm font-bold">
              <AlertCircle size={18} /> {error}
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Username</label>
              <div className="relative">
                <UserIcon className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
                <input 
                  type="text" 
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  className="w-full pl-14 pr-6 py-5 bg-slate-50 border rounded-2xl outline-none focus:ring-4 focus:ring-emerald-500/10 focus:border-emerald-500 transition-all font-bold"
                  required
                />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Password</label>
              <div className="relative">
                <Lock className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
                <input 
                  type={showPassword ? 'text' : 'password'}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full pl-14 pr-14 py-5 bg-slate-50 border rounded-2xl outline-none focus:ring-4 focus:ring-emerald-500/10 focus:border-emerald-500 transition-all font-bold"
                  required
                />
                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400">
                  {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                </button>
              </div>
            </div>

            <button disabled={loading} className="w-full py-5 bg-emerald-600 text-white rounded-2xl font-black text-lg shadow-xl hover:bg-emerald-700 transition-all disabled:opacity-50">
              {loading ? <RefreshCw className="animate-spin mx-auto" size={24} /> : 'Masuk Ke Sistem'}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useEffect } from 'react';
import { ArrowLeft, Loader2, Eye, EyeOff } from 'lucide-react';
import { User, ClassRoom } from '../types';
import { auth, firestore } from '../firebase.ts';
import { createUserWithEmailAndPassword } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js";
import { doc, setDoc, getDocs, collection } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js";

interface SignupProps {
  onBack: () => void;
  onSignup: () => void;
  logoUrl: string;
}

const Signup: React.FC<SignupProps> = ({ onBack, onSignup, logoUrl }) => {
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [classRoom, setClassRoom] = useState('');
  const [classes, setClasses] = useState<ClassRoom[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const fetchClasses = async () => {
      const querySnapshot = await getDocs(collection(firestore, "elearning_classes_list"));
      setClasses(querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })) as ClassRoom[]);
    };
    fetchClasses();
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    const email = `${username.trim().toLowerCase()}@alirsyad.sch.id`;

    try {
      const userCredential = await createUserWithEmailAndPassword(auth, email, password);
      const firebaseUser = userCredential.user;

      const userData: User = {
        id: firebaseUser.uid,
        name,
        username: username.toLowerCase(),
        classId: classRoom,
        role: 'STUDENT',
        status: 'PENDING',
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${username}`
      };

      await setDoc(doc(firestore, "users", firebaseUser.uid), userData);

      alert("Pendaftaran berhasil! Tunggu konfirmasi Guru untuk aktifkan akun.");
      await auth.signOut();
      onSignup();
    } catch (err: any) {
      alert("Error: " + err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col justify-center items-center px-6 py-12">
      <div className="w-full max-w-xl bg-white p-12 rounded-[2.5rem] shadow-2xl relative overflow-hidden">
        {loading && <div className="absolute inset-0 bg-white/80 z-20 flex items-center justify-center"><Loader2 className="animate-spin text-emerald-600" size={40} /></div>}
        <button onClick={onBack} className="flex items-center gap-2 text-slate-500 mb-8"><ArrowLeft size={18} /> Kembali</button>
        <h3 className="text-3xl font-black text-slate-900 mb-8 text-center">Registrasi Cloud</h3>

        <form onSubmit={handleSubmit} className="space-y-6">
          {step === 1 ? (
            <div className="space-y-6 animate-in slide-in-from-right-4">
              <div><label className="block text-sm font-bold mb-2">Nama Lengkap</label><input value={name} onChange={e => setName(e.target.value)} className="w-full p-4 bg-slate-50 border rounded-2xl outline-none font-bold" placeholder="Nama Lengkap" required /></div>
              <div>
                <label className="block text-sm font-bold mb-2">Pilih Kelas</label>
                <select value={classRoom} onChange={e => setClassRoom(e.target.value)} className="w-full p-4 bg-slate-50 border rounded-2xl outline-none font-bold" required>
                  <option value="">-- Pilih Kelas --</option>
                  {classes.map(c => <option key={c.id} value={c.name}>Kelas {c.name}</option>)}
                </select>
              </div>
              <button type="button" onClick={() => setStep(2)} className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black text-lg">Lanjut Langkah 2</button>
            </div>
          ) : (
            <div className="space-y-6 animate-in slide-in-from-right-4">
              <div><label className="block text-sm font-bold mb-2">Username Baru</label><input value={username} onChange={e => setUsername(e.target.value)} className="w-full p-4 bg-slate-50 border rounded-2xl outline-none font-bold" placeholder="Username" required /></div>
              <div>
                <label className="block text-sm font-bold mb-2">Password Baru</label>
                <div className="relative">
                  <input type={showPassword ? 'text' : 'password'} value={password} onChange={e => setPassword(e.target.value)} className="w-full p-4 bg-slate-50 border rounded-2xl outline-none font-bold" placeholder="Password" required />
                  <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-4 top-1/2 -translate-y-1/2">{showPassword ? <EyeOff size={20} /> : <Eye size={20} />}</button>
                </div>
              </div>
              <div className="flex gap-4">
                <button type="button" onClick={() => setStep(1)} className="flex-1 py-4 bg-slate-100 rounded-2xl font-bold">Kembali</button>
                <button type="submit" className="flex-[2] py-4 bg-emerald-600 text-white rounded-2xl font-black">Buat Akun Sekarang</button>
              </div>
            </div>
          )}
        </form>
      </div>
    </div>
  );
};

export default Signup;

