        <p className="text-slate-500 max-w-sm mb-8 leading-relaxed">
          Gagal menghubungi server database. Periksa koneksi internet Anda atau hubungi admin.
        </p>
        <button 
          onClick={() => window.location.reload()}
          className="px-8 py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-emerald-600 transition-all shadow-xl active:scale-95"
        >
          Coba Muat Ulang
        </button>
      </div>
    );
  }

  return (
    <div className="min-h-screen selection:bg-emerald-100 selection:text-emerald-900 relative">
      {/* Cloud Sync Status Indicator */}
      <div className={`fixed top-6 left-1/2 -translate-x-1/2 z-[100] flex items-center gap-3 px-6 py-3 rounded-full shadow-2xl border backdrop-blur-md transition-all duration-500 transform ${
        syncStatus === 'idle' ? 'translate-y-[-120%] opacity-0' : 'translate-y-0 opacity-100'
      } ${
        syncStatus === 'syncing' ? 'bg-indigo-600 text-white border-indigo-500' : 
        syncStatus === 'success' ? 'bg-emerald-600 text-white border-emerald-500' : 'bg-rose-600 text-white border-rose-500'
      }`}>
        {syncStatus === 'syncing' && <RefreshCw className="animate-spin" size={16} />}
        {syncStatus === 'success' && <CheckCircle size={16} />}
        {syncStatus === 'error' && <AlertCircle size={16} />}
        <span className="text-[10px] font-black uppercase tracking-[0.2em]">
          {syncStatus === 'syncing' ? 'Firestore Sinkronisasi...' : 
           syncStatus === 'success' ? 'Data Cloud Terupdate' : 'Gagal Sinkronisasi'}
        </span>
      </div>

      {view === 'landing' && <LandingPage onNavigateLogin={(role) => { setLoginRole(role); setView('login'); }} onNavigateSignup={() => setView('signup')} settings={settings} />}
      {view === 'login' && <Login role={loginRole || 'STUDENT'} onBack={() => setView('landing')} onLogin={handleLogin} onNavigateSignup={() => setView('signup')} />}
      {view === 'signup' && <Signup onBack={() => setView('login')} onSignup={() => { setLoginRole('STUDENT'); setView('login'); }} logoUrl={settings.logoUrl} />}
      {view === 'dashboard' && user && (
        user.role === 'ADMIN' 
          ? <AdminDashboard user={user} onLogout={handleLogout} settings={settings} setSettings={setSettings} onUpdateUser={setUser} /> 
          : <StudentDashboard user={user} onLogout={handleLogout} settings={settings} onUpdateUser={setUser} />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ArrowLeft, Lock, User as UserIcon, Loader2, Eye, EyeOff, AlertCircle, RefreshCw, ShieldCheck, Sparkles } from 'lucide-react';
import { Role, User } from '../types';
import { auth, firestore } from '../firebase.ts';
import { signInWithEmailAndPassword, createUserWithEmailAndPassword } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js";
import { doc, getDoc, getDocs, collection, setDoc } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js";

interface LoginProps {
  role: Role;
  onBack: () => void;
  onLogin: (user: User) => void;
  onNavigateSignup: () => void;
}

const Login: React.FC<LoginProps> = ({ role, onBack, onLogin, onNavigateSignup }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [isEmptyDb, setIsEmptyDb] = useState(false);
  const [isInitializing, setIsInitializing] = useState(false);

  // Cek apakah database kosong (untuk bantuan setup awal)
  useEffect(() => {
    const checkUsers = async () => {
      try {
        const querySnapshot = await getDocs(collection(firestore, "users"));
        if (querySnapshot.empty) {
          setIsEmptyDb(true);
        }
      } catch (e) {
        console.warn("Could not check users collection status");
      }
    };
    checkUsers();
  }, []);

  const handleCreateInitialAdmin = async () => {
    setIsInitializing(true);
    setError('');
    const adminUsername = "admin";
    const adminPass = "admin123";
    const email = `${adminUsername}@alirsyad.sch.id`;

    try {
      // 1. Create Auth User
      const userCredential = await createUserWithEmailAndPassword(auth, email, adminPass);
      const firebaseUser = userCredential.user;

      // 2. Create Firestore Profile
      const adminData: User = {
        id: firebaseUser.uid,
        name: "Admin Utama Informatika",
        username: adminUsername,
        role: 'ADMIN',
        status: 'ACTIVE',
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=admin`
      };

      await setDoc(doc(firestore, "users", firebaseUser.uid), adminData);

      alert(`Akun Admin Berhasil Dibuat!\n\nUsername: ${adminUsername}\nPassword: ${adminPass}\n\nSilakan login sekarang.`);
      setIsEmptyDb(false);
      setUsername(adminUsername);
      setPassword(adminPass);
    } catch (err: any) {
      setError("Gagal inisialisasi: " + err.message);
    } finally {
      setIsInitializing(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    const email = `${username.trim().toLowerCase()}@alirsyad.sch.id`;

    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      const firebaseUser = userCredential.user;

      const userDoc = await getDoc(doc(firestore, "users", firebaseUser.uid));

      if (userDoc.exists()) {
        const userData = userDoc.data() as User;
        if (userData.role !== role) {
          await auth.signOut();
          setError(`Akun ini tidak terdaftar sebagai ${role}. Silakan kembali ke menu utama.`);
        } else if (userData.status === 'PENDING') {
          await auth.signOut();
          setError("Akun Anda masih menunggu persetujuan Guru.");
        } else {
          onLogin({ ...userData, id: firebaseUser.uid });
        }
      } else {
        setError("Profil pengguna tidak ditemukan di database.");
      }
    } catch (err: any) {
      console.error(err);
      if (err.code === 'auth/user-not-found') setError("Username tidak ditemukan.");
      else if (err.code === 'auth/wrong-password') setError("Password salah.");
      else if (err.code === 'auth/invalid-credential') setError("Username atau password salah.");
      else setError("Gagal login: " + err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-white">
      <div className="hidden md:flex flex-1 bg-slate-900 items-center justify-center p-20 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-80 h-80 bg-emerald-500/20 rounded-full blur-[100px] -mr-40 -mt-40"></div>
        <div className="absolute bottom-0 left-0 w-64 h-64 bg-blue-500/10 rounded-full blur-[80px] -ml-32 -mb-32"></div>

        <div className="relative z-10 text-white max-w-md space-y-6">
          <div className="w-16 h-16 bg-emerald-500 rounded-2xl flex items-center justify-center shadow-2xl shadow-emerald-500/20">
             <ShieldCheck size={32} />
          </div>
          <h2 className="text-5xl font-black leading-tight tracking-tight">Portal <br/><span className="text-emerald-500">{role === 'ADMIN' ? 'Guru' : 'Siswa'}</span></h2>
          <p className="text-xl text-slate-400 font-medium">Sistem E-Learning Informatika Berbasis Firebase Cloud Terenkripsi.</p>
        </div>
      </div>

      <div className="flex-1 bg-white flex flex-col justify-center items-center px-6 py-12">
        <div className="w-full max-w-md">
          <button onClick={onBack} className="flex items-center gap-2 text-slate-400 hover:text-slate-800 mb-10 font-bold group">
            <ArrowLeft size={18} className="group-hover:-translate-x-1 transition-transform" /> Kembali ke Landing
          </button>

          <h3 className="text-4xl font-black text-slate-900 mb-2 tracking-tight">Login Cloud</h3>
          <p className="text-slate-500 mb-8 font-medium italic">Akses dashboard pembelajaran Anda.</p>

          {error && (
            <div className="mb-6 p-4 bg-rose-50 border border-rose-100 rounded-2xl flex items-center gap-3 text-rose-600 text-sm font-bold animate-in fade-in slide-in-from-top-2">
              <AlertCircle size={18} className="shrink-0" /> {error}
            </div>
          )}

          {isEmptyDb && (
            <div className="mb-8 p-6 bg-indigo-50 border border-indigo-100 rounded-[2rem] space-y-4">
               <div className="flex items-center gap-3 text-indigo-700">
                  <Sparkles size={20} />
                  <p className="font-black text-xs uppercase tracking-widest">Database Baru Terdeteksi</p>
               </div>
               <p className="text-xs text-indigo-600 leading-relaxed font-medium">Belum ada user di database Anda. Anda bisa membuat akun Admin pertama secara otomatis di sini.</p>
               <button 
                onClick={handleCreateInitialAdmin}
                disabled={isInitializing}
                className="w-full py-3 bg-indigo-600 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 transition-all flex items-center justify-center gap-2"
               >
                 {isInitializing ? <RefreshCw className="animate-spin" size={14} /> : <UserIcon size={14} />}
                 Buat Admin Pertama (admin / admin123)
               </button>
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Username</label>
              <div className="relative group">
                <UserIcon className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-emerald-500 transition-colors" size={20} />
                <input 
                  type="text" 
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  placeholder="admin atau nama_pengguna"
                  className="w-full pl-14 pr-6 py-5 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none focus:ring-4 focus:ring-emerald-500/10 focus:border-emerald-500 transition-all font-bold text-slate-800 placeholder:text-slate-300"
                  required
                />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Password</label>
              <div className="relative group">
                <Lock className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-emerald-500 transition-colors" size={20} />
                <input 
                  type={showPassword ? 'text' : 'password'}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="••••••••"
                  className="w-full pl-14 pr-14 py-5 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none focus:ring-4 focus:ring-emerald-500/10 focus:border-emerald-500 transition-all font-bold text-slate-800 placeholder:text-slate-300"
                  required
                />
                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 hover:text-emerald-500 transition-colors">
                  {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                </button>
              </div>
            </div>

            <button disabled={loading} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-lg shadow-2xl shadow-slate-200 hover:bg-emerald-600 transition-all disabled:opacity-50 active:scale-[0.98] flex items-center justify-center gap-3">
              {loading ? <RefreshCw className="animate-spin" size={24} /> : 'Masuk Ke Sistem'}
            </button>

            {role === 'STUDENT' && (
              <p className="text-center text-sm font-medium text-slate-400 mt-8">
                Belum punya akun? <button type="button" onClick={onNavigateSignup} className="text-emerald-600 font-black hover:underline">Daftar Sekarang</button>
              </p>
            )}
          </form>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useEffect } from 'react';
import { ArrowLeft, Lock, User as UserIcon, Loader2, Eye, EyeOff, AlertCircle, RefreshCw, ShieldCheck, Sparkles, ExternalLink } from 'lucide-react';
import { Role, User } from '../types';
import { auth, firestore } from '../firebase.ts';
