        setError({
          message: "Metode Login 'Email/Password' dinonaktifkan di Firebase Console. Wajib diaktifkan!",
          isAuthError: true
        });
      } else {
        setError({message: "Terjadi kesalahan: " + (err.message || "Gagal menghubungi server")});
