              setForm({ name: '', username: '', password: '', classId: '', avatar: '' }); 
              setShowModal(true); 
            }} 
            className="group px-6 py-3 bg-blue-600 text-white rounded-xl font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-2 shadow-xl hover:bg-blue-700 active:scale-95 transition-all"
          >
            <UserPlus2 size={16} /> 
            Tambah Siswa
          </button>
