import React, { useState, useEffect } from 'react';
import { 
  ArrowLeft, Lock, User as UserIcon, Loader2, Eye, EyeOff, 
  AlertCircle, RefreshCw, ShieldCheck, Sparkles, ExternalLink,
  GraduationCap, Briefcase, Database, CheckCircle2, ChevronRight
} from 'lucide-react';
import { Role, User } from '../types';
import { auth, firestore } from '../firebase.ts';
import { signInWithEmailAndPassword, createUserWithEmailAndPassword } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-auth.js";
import { doc, getDoc, getDocs, collection, setDoc, query, where } from "https://www.gstatic.com/firebasejs/10.8.0/firebase-firestore.js";

interface LoginProps {
  role: Role;
  onBack: () => void;
  onLogin: (user: User) => void;
  onNavigateSignup: () => void;
}

const Login: React.FC<LoginProps> = ({ role, onBack, onLogin, onNavigateSignup }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState<{message: string, isAuthError?: boolean}>({message: ''});
  const [loading, setLoading] = useState(false);
  const [isEmptyDb, setIsEmptyDb] = useState(false);
  const [isInitializing, setIsInitializing] = useState(false);

  const isStudent = role === 'STUDENT';
  const themeColor = isStudent ? 'indigo' : 'emerald';

  useEffect(() => {
    const checkUsers = async () => {
      try {
        const querySnapshot = await getDocs(collection(firestore, "users"));
        if (querySnapshot.empty) {
          setIsEmptyDb(true);
        }
      } catch (e) {
        console.warn("Koneksi Firestore belum siap.");
      }
    };
    checkUsers();
  }, []);

  const handleCreateInitialAdmin = async () => {
    setIsInitializing(true);
    setError({message: ''});
    const adminUsername = "admin";
    const adminPass = "admin123";
    const email = `${adminUsername}@alirsyad.sch.id`;

    try {
      const userCredential = await createUserWithEmailAndPassword(auth, email, adminPass);
      const firebaseUser = userCredential.user;

      const adminData: User = {
        id: firebaseUser.uid,
        name: "Administrator Informatika",
        username: adminUsername,
        role: 'ADMIN',
        status: 'ACTIVE',
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=admin`
      };

      await setDoc(doc(firestore, "users", firebaseUser.uid), adminData);

      alert(`AKUN ADMIN BERHASIL DIBUAT!\n\nUsername: ${adminUsername}\nPassword: ${adminPass}`);
      setIsEmptyDb(false);
      setUsername(adminUsername);
      setPassword(adminPass);
    } catch (err: any) {
      setError({message: "Gagal inisialisasi: " + err.message});
    } finally {
      setIsInitializing(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError({message: ''});
    setLoading(true);

    const cleanUsername = username.trim().toLowerCase();
    const email = `${cleanUsername}@alirsyad.sch.id`;

    try {
      // 1. Proses Autentikasi Firebase
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      const firebaseUser = userCredential.user;

      // 2. Cari Profil di Database (users atau elearning_students_list)
      let userDoc = await getDoc(doc(firestore, "users", firebaseUser.uid));
      let userData: User | null = null;

      if (userDoc.exists()) {
        userData = userDoc.data() as User;
      } else {
        userDoc = await getDoc(doc(firestore, "elearning_students_list", firebaseUser.uid));
        if (userDoc.exists()) {
          userData = userDoc.data() as User;
        }
      }

      if (userData) {
        // 3. Validasi Role
        if (userData.role !== role) {
          await auth.signOut();
          setError({message: `Akses Ditolak: Anda masuk ke Portal ${isStudent ? 'Siswa' : 'Guru'}, tetapi akun ini terdaftar sebagai ${userData.role === 'ADMIN' ? 'Guru' : 'Siswa'}.`});
        } else if (userData.status === 'PENDING') {
          await auth.signOut();
          setError({message: "Akun Anda belum disetujui. Silakan hubungi Guru Informatika."});
        } else {
          onLogin({ ...userData, id: firebaseUser.uid });
        }
      } else {
        setError({message: "Data profil tidak sinkron. Silakan daftar ulang."});
      }
    } catch (err: any) {
      console.error("Login Error Code:", err.code);

      if (err.code === 'auth/invalid-credential' || err.code === 'auth/wrong-password' || err.code === 'auth/user-not-found') {
        // Cek apakah username terdaftar di Firestore elearning_students_list
        try {
          const q = query(
            collection(firestore, isStudent ? "elearning_students_list" : "users"), 
            where("username", "==", cleanUsername)
          );
          const snapshot = await getDocs(q);

          if (snapshot.empty) {
            setError({message: `Username '${cleanUsername}' tidak terdaftar di database ${isStudent ? 'Siswa' : 'Guru'}. Pastikan Anda sudah mendaftar.`});
          } else {
            setError({message: "Password yang Anda masukkan salah. Silakan coba lagi."});
          }
        } catch (dbErr) {
          setError({message: "Username atau Password salah. Pastikan data sudah benar."});
        }
      } else {
        setError({message: "Terjadi kesalahan sistem: " + (err.message || "Gagal terhubung.")});
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-white font-['Plus_Jakarta_Sans']">
      {/* SISI KIRI: ILUSTRASI DINAMIS */}
      <div className={`hidden md:flex flex-1 items-center justify-center p-20 relative overflow-hidden transition-colors duration-700 ${isStudent ? 'bg-indigo-900' : 'bg-slate-900'}`}>
        <div className={`absolute top-0 right-0 w-[500px] h-[500px] rounded-full blur-[120px] -mr-64 -mt-64 opacity-20 ${isStudent ? 'bg-blue-400' : 'bg-emerald-400'}`}></div>
        <div className={`absolute bottom-0 left-0 w-80 h-80 rounded-full blur-[100px] -ml-40 -mb-40 opacity-10 ${isStudent ? 'bg-indigo-400' : 'bg-slate-400'}`}></div>

        <div className="relative z-10 text-white max-w-md space-y-8">
          <div className={`w-20 h-20 rounded-3xl flex items-center justify-center shadow-2xl animate-in zoom-in duration-500 ${isStudent ? 'bg-indigo-500' : 'bg-emerald-500'}`}>
             {isStudent ? <GraduationCap size={40} /> : <Briefcase size={40} />}
          </div>
          <div className="space-y-4">
            <h2 className="text-6xl font-black leading-tight tracking-tighter">
              Portal <br/>
              <span className={isStudent ? 'text-indigo-400' : 'text-emerald-400'}>
                {isStudent ? 'Belajar Siswa' : 'Manajemen Guru'}
              </span>
            </h2>
            <p className="text-xl text-slate-400 font-medium leading-relaxed italic">
              Akses sistem pembelajaran Informatika berbasis Cloud SMP Al Irsyad Surakarta.
            </p>
          </div>

          <div className="pt-10 flex items-center gap-4">
             <div className="flex -space-x-3">
                {[1,2,3,4].map(i => (
                  <img key={i} src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${i + (isStudent ? 10 : 0)}`} className="w-10 h-10 rounded-full border-2 border-slate-900 bg-slate-800" alt="" />
                ))}
             </div>
             <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">
               {isStudent ? '1200+ Siswa Aktif' : 'Tim Guru Informatika'}
             </p>
          </div>
        </div>
      </div>

      {/* SISI KANAN: FORM LOGIN */}
      <div className="flex-1 bg-white flex flex-col justify-center items-center px-8 py-12 md:px-20">
        <div className="w-full max-w-sm">
          <button onClick={onBack} className="flex items-center gap-2 text-slate-400 hover:text-slate-800 mb-12 font-bold group transition-colors">
            <ArrowLeft size={18} className="group-hover:-translate-x-1 transition-transform" /> Kembali ke Beranda
          </button>

          <div className="mb-10">
            <h3 className="text-4xl font-black text-slate-900 mb-2 tracking-tight">Login {isStudent ? 'Siswa' : 'Guru'}</h3>
            <p className="text-slate-500 font-medium italic">Silakan masuk menggunakan akun Cloud Anda.</p>
          </div>

          {error.message && (
            <div className="mb-8 p-5 bg-rose-50 border border-rose-100 text-rose-600 rounded-2xl animate-in fade-in slide-in-from-top-2 duration-300">
              <div className="flex items-start gap-3">
                <AlertCircle size={20} className="shrink-0 mt-0.5" />
                <p className="text-sm font-bold leading-relaxed">{error.message}</p>
              </div>
            </div>
          )}

          {isEmptyDb && !isStudent && (
            <div className="mb-8 p-6 bg-amber-50 border border-amber-100 rounded-[2rem] space-y-4">
               <div className="flex items-center gap-3 text-amber-700">
                  <Sparkles size={20} />
                  <p className="font-black text-[10px] uppercase tracking-widest">Inisialisasi Sistem</p>
               </div>
               <p className="text-xs text-amber-600 leading-relaxed font-medium">Belum ada akun Guru terdaftar. Klik tombol di bawah untuk membuat admin pertama.</p>
               <button 
                onClick={handleCreateInitialAdmin}
                disabled={isInitializing}
                className="w-full py-4 bg-amber-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-amber-700 transition-all flex items-center justify-center gap-3 shadow-xl disabled:opacity-50"
               >
                 {isInitializing ? <RefreshCw className="animate-spin" size={16} /> : <ShieldCheck size={16} />}
                 Daftarkan Guru (admin)
               </button>
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-6 text-black">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Username</label>
              <div className="relative group">
                <div className={`absolute left-5 top-1/2 -translate-y-1/2 transition-colors duration-300 ${isStudent ? 'group-focus-within:text-indigo-500 text-slate-300' : 'group-focus-within:text-emerald-500 text-slate-300'}`}>
                  <UserIcon size={20} />
                </div>
                <input 
                  type="text" 
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  placeholder={isStudent ? "Contoh: ahmad_8a" : "Username Guru"}
                  className={`w-full pl-14 pr-6 py-5 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none transition-all font-bold text-slate-800 placeholder:text-slate-300 shadow-inner ${isStudent ? 'focus:ring-4 focus:ring-indigo-500/5 focus:border-indigo-500' : 'focus:ring-4 focus:ring-emerald-500/5 focus:border-emerald-500'}`}
                  required
                />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Password</label>
              <div className="relative group">
                <div className={`absolute left-5 top-1/2 -translate-y-1/2 transition-colors duration-300 ${isStudent ? 'group-focus-within:text-indigo-500 text-slate-300' : 'group-focus-within:text-emerald-500 text-slate-300'}`}>
                  <Lock size={20} />
                </div>
                <input 
                  type={showPassword ? 'text' : 'password'}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="••••••••"
                  className={`w-full pl-14 pr-14 py-5 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none transition-all font-bold text-slate-800 placeholder:text-slate-300 shadow-inner ${isStudent ? 'focus:ring-4 focus:ring-indigo-500/5 focus:border-indigo-500' : 'focus:ring-4 focus:ring-emerald-500/5 focus:border-emerald-500'}`}
                  required
                />
                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 transition-colors">
                  {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                </button>
              </div>
            </div>

            <button 
              disabled={loading} 
              className={`w-full py-5 text-white rounded-2xl font-black text-lg shadow-2xl transition-all disabled:opacity-50 active:scale-[0.98] flex items-center justify-center gap-3 ${isStudent ? 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100' : 'bg-slate-900 hover:bg-emerald-600 shadow-slate-100'}`}
            >
              {loading ? <Loader2 className="animate-spin" size={24} /> : 'Login Ke Portal'}
            </button>

            {isStudent && (
              <p className="text-center text-sm font-medium text-slate-400 mt-8">
                Belum terdaftar? <button type="button" onClick={onNavigateSignup} className="text-indigo-600 font-black hover:underline">Daftar Sekarang</button>
              </p>
            )}

            <div className="pt-10 flex flex-col items-center gap-3">
               <div className="flex items-center gap-2 px-4 py-2 bg-slate-50 rounded-full border border-slate-100">
                  <Database size={14} className="text-slate-400" />
                  <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Informatika Cloud v2.0</span>
               </div>
               <p className="text-[10px] text-slate-300 font-bold uppercase tracking-tight">SMP AL Irsyad Surakarta</p>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

