import { 
  auth, 
  firestore, 
  onAuthStateChanged, 
  collection, 
  doc, 
  getDoc, 
  getDocs, 
  setDoc, 
  addDoc,
  signOut as firebaseSignOut
} from './firebase.ts';

const sanitize = (obj: any) => {
  const result: any = {};
  Object.keys(obj).forEach(key => {
    if (obj[key] !== undefined) result[key] = obj[key];
  });
  return result;
};

export const db = {
  get: async (key: string) => {
    try {
      const querySnapshot = await getDocs(collection(firestore, key));
      return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
    } catch (err) {
      console.error("Firestore Get Error:", err);
      return [];
    }
  },
  getSingle: async (key: string, id: string) => {
    try {
      const docSnap = await getDoc(doc(firestore, key, id));
      return docSnap.exists() ? { id: docSnap.id, ...docSnap.data() } : null;
    } catch (err) {
      console.error("Firestore GetSingle Error:", err);
      return null;
    }
  },
  saveAll: async (key: string, value: any) => {
    window.dispatchEvent(new CustomEvent('sync-start'));
    try {
      if (Array.isArray(value)) {
        for (const item of value) {
          const id = item.id || Math.random().toString(36).substr(2, 9);
          await setDoc(doc(firestore, key, id), sanitize(item), { merge: true });
        }
      } else {
        await setDoc(doc(firestore, "settings", key), sanitize(value), { merge: true });
      }
      window.dispatchEvent(new CustomEvent('sync-end'));
    } catch (err) {
      window.dispatchEvent(new CustomEvent('sync-error'));
      throw err;
    }
  },
  append: async (key: string, value: any) => {
    window.dispatchEvent(new CustomEvent('sync-start'));
    try {
      const id = value.id || undefined;
      if (id) {
        await setDoc(doc(firestore, key, id), sanitize(value));
      } else {
        await addDoc(collection(firestore, key), sanitize(value));
      }
      window.dispatchEvent(new CustomEvent('sync-end'));
    } catch (err) {
      window.dispatchEvent(new CustomEvent('sync-error'));
      throw err;
    }
  },
  deleteKey: async (key: string) => {
    console.warn("Delete functionality restricted on client.");
  }
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<'landing' | 'login' | 'signup' | 'dashboard'>('landing');
  const [loginRole, setLoginRole] = useState<Role | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [syncStatus, setSyncStatus] = useState<'idle' | 'syncing' | 'success' | 'error'>('idle');
  const [settings, setSettings] = useState<SiteSettings>({
    logoUrl: 'https://www.alirsyad.or.id/wp-content/uploads/download/alirsyad-alislamiyyah.png',
    heroImageUrl: 'https://cdn.fpt-is.com/vi/he-thong-elearning-1.png',
    siteName: 'Informatika SMP Al Irsyad Surakarta'
  });

  // Listen for Auth changes once
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
      try {
        if (firebaseUser) {
          let userProfile = await db.getSingle('users', firebaseUser.uid);
          if (!userProfile) userProfile = await db.getSingle('elearning_students_list', firebaseUser.uid);
          if (!userProfile) userProfile = await db.getSingle('elearning_pending_students', firebaseUser.uid);

          if (userProfile) {
            setUser(userProfile as User);
            setView('dashboard');
          }
        } else {
          setUser(null);
          // Only redirect if we're not currently in login/signup
          setView(prev => prev === 'dashboard' ? 'landing' : prev);
        }
      } catch (err) {
        console.error("Auth sync error:", err);
      } finally {
        setIsLoading(false);
      }
    });

    const fetchSettings = async () => {
      try {
        const stored = await getDoc(doc(firestore, "settings", "site_configs"));
        if (stored.exists()) setSettings(stored.data() as SiteSettings);
      } catch (e) {
        console.warn("Settings fetch failed:", e);
      }
    };

    fetchSettings();
    return () => unsubscribe();
  }, []);

  useEffect(() => {
    const handleSyncStart = () => setSyncStatus('syncing');
    const handleSyncEnd = () => {
      setSyncStatus('success');
      setTimeout(() => setSyncStatus('idle'), 3000);
    };
    const handleSyncError = () => {
      setSyncStatus('error');
      setTimeout(() => setSyncStatus('idle'), 5000);
    };

    window.addEventListener('sync-start', handleSyncStart);
    window.addEventListener('sync-end', handleSyncEnd);
    window.addEventListener('sync-error', handleSyncError);

    return () => {
      window.removeEventListener('sync-start', handleSyncStart);
      window.removeEventListener('sync-end', handleSyncEnd);
      window.removeEventListener('sync-error', handleSyncError);
    };
  }, []);

  const handleLogin = (u: User) => {
    setUser(u);
    setView('dashboard');
  };

  const handleLogout = async () => {
    await firebaseSignOut(auth);
    setUser(null);
    setView('landing');
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 text-center">
        <div className="relative mb-8">
          <div className="w-20 h-20 border-4 border-emerald-100 border-t-emerald-600 rounded-full animate-spin"></div>
          <Cloud className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-emerald-600" size={28} />
        </div>
        <h2 className="text-xl font-black text-slate-800 mb-2 tracking-tight">Menghubungkan ke Cloud...</h2>
        <p className="text-slate-400 font-bold uppercase text-[10px] tracking-[0.3em]">SMP AL Irsyad Surakarta</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen selection:bg-emerald-100 selection:text-emerald-900 relative">
      <div className={`fixed top-6 left-1/2 -translate-x-1/2 z-[100] flex items-center gap-3 px-6 py-3 rounded-full shadow-2xl border backdrop-blur-md transition-all duration-500 transform ${
        syncStatus === 'idle' ? 'translate-y-[-120%] opacity-0' : 'translate-y-0 opacity-100'
      } ${
        syncStatus === 'syncing' ? 'bg-indigo-600 text-white border-indigo-500' : 
        syncStatus === 'success' ? 'bg-emerald-600 text-white border-emerald-500' : 'bg-rose-600 text-white border-rose-500'
      }`}>
        {syncStatus === 'syncing' && <RefreshCw className="animate-spin" size={16} />}
        {syncStatus === 'success' && <CheckCircle size={16} />}
        {syncStatus === 'error' && <AlertCircle size={16} />}
        <span className="text-[10px] font-black uppercase tracking-[0.2em]">
          {syncStatus === 'syncing' ? 'Firestore Sinkronisasi...' : 
           syncStatus === 'success' ? 'Data Cloud Terupdate' : 'Gagal Sinkronisasi'}
        </span>
      </div>

      {view === 'landing' && <LandingPage onNavigateLogin={(role) => { setLoginRole(role); setView('login'); }} onNavigateSignup={() => setView('signup')} settings={settings} />}
      {view === 'login' && <Login role={loginRole || 'STUDENT'} onBack={() => setView('landing')} onLogin={handleLogin} onNavigateSignup={() => setView('signup')} />}
      {view === 'signup' && <Signup onBack={() => setView('login')} onSignup={() => { setLoginRole('STUDENT'); setView('login'); }} logoUrl={settings.logoUrl} />}
      {view === 'dashboard' && user && (
        user.role === 'ADMIN' 
          ? <AdminDashboard user={user} onLogout={handleLogout} settings={settings} setSettings={setSettings} onUpdateUser={setUser} /> 
          : <StudentDashboard user={user} onLogout={handleLogout} settings={settings} onUpdateUser={setUser} />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { 
  ArrowLeft, Lock, User as UserIcon, Loader2, Eye, EyeOff, 
  AlertCircle, RefreshCw, ShieldCheck, Sparkles, 
  GraduationCap, Briefcase, Database
} from 'lucide-react';
import { Role, User } from '../types';
import { 
  auth, 
  firestore, 
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword, 
  doc, 
  getDoc, 
  getDocs, 
  collection, 
  setDoc, 
  query, 
  where 
} from '../firebase.ts';

interface LoginProps {
  role: Role;
  onBack: () => void;
  onLogin: (user: User) => void;
  onNavigateSignup: () => void;
}

const Login: React.FC<LoginProps> = ({ role, onBack, onLogin, onNavigateSignup }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState<{message: string}>({message: ''});
  const [loading, setLoading] = useState(false);
  const [isEmptyDb, setIsEmptyDb] = useState(false);
  const [isInitializing, setIsInitializing] = useState(false);

  const isStudent = role === 'STUDENT';

  useEffect(() => {
    const checkUsers = async () => {
      try {
        const querySnapshot = await getDocs(collection(firestore, "users"));
        if (querySnapshot.empty) setIsEmptyDb(true);
      } catch (e) {
        console.warn("Firestore connection not ready yet.");
      }
    };
    checkUsers();
  }, []);

  const handleCreateInitialAdmin = async () => {
    setIsInitializing(true);
    setError({message: ''});
    const adminUsername = "admin";
    const adminPass = "admin123";
    const email = `${adminUsername}@alirsyad.sch.id`;

    try {
      const userCredential = await createUserWithEmailAndPassword(auth, email, adminPass);
      const firebaseUser = userCredential.user;

      const adminData: User = {
        id: firebaseUser.uid,
        name: "Administrator Informatika",
        username: adminUsername,
        role: 'ADMIN',
        status: 'ACTIVE',
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=admin`
      };

      await setDoc(doc(firestore, "users", firebaseUser.uid), adminData);
      alert(`AKUN ADMIN BERHASIL DIBUAT!\n\nUsername: ${adminUsername}\nPassword: ${adminPass}`);
      setIsEmptyDb(false);
      setUsername(adminUsername);
      setPassword(adminPass);
    } catch (err: any) {
      setError({message: "Gagal inisialisasi: " + err.message});
    } finally {
      setIsInitializing(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError({message: ''});
    setLoading(true);

    const cleanUsername = username.trim().toLowerCase();
    const email = `${cleanUsername}@alirsyad.sch.id`;

    try {
      const userCredential = await signInWithEmailAndPassword(auth, email, password);
      const firebaseUser = userCredential.user;

      let userDoc = await getDoc(doc(firestore, "users", firebaseUser.uid));
      let userData: User | null = null;

      if (userDoc.exists()) {
        userData = userDoc.data() as User;
      } else {
        userDoc = await getDoc(doc(firestore, "elearning_students_list", firebaseUser.uid));
        if (userDoc.exists()) userData = userDoc.data() as User;
      }

      if (userData) {
        if (userData.role !== role) {
          await auth.signOut();
          setError({message: `Akses Ditolak: Akun ini terdaftar sebagai ${userData.role}.`});
        } else if (userData.status === 'PENDING') {
          await auth.signOut();
          setError({message: "Akun Anda belum disetujui Guru."});
        } else {
          onLogin({ ...userData, id: firebaseUser.uid });
        }
      } else {
        setError({message: "Profil tidak ditemukan. Silakan hubungi admin."});
      }
    } catch (err: any) {
      if (err.code === 'auth/invalid-credential' || err.code === 'auth/wrong-password') {
        setError({message: "Username atau Password salah."});
      } else {
        setError({message: "Login gagal: " + (err.message || "Kesalahan sistem.")});
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-white font-['Plus_Jakarta_Sans']">
      <div className={`hidden md:flex flex-1 items-center justify-center p-20 relative overflow-hidden transition-colors duration-700 ${isStudent ? 'bg-indigo-900' : 'bg-slate-900'}`}>
        <div className={`absolute top-0 right-0 w-[500px] h-[500px] rounded-full blur-[120px] -mr-64 -mt-64 opacity-20 ${isStudent ? 'bg-blue-400' : 'bg-emerald-400'}`}></div>
        <div className="relative z-10 text-white max-w-md space-y-8">
          <div className={`w-20 h-20 rounded-3xl flex items-center justify-center shadow-2xl ${isStudent ? 'bg-indigo-500' : 'bg-emerald-500'}`}>
             {isStudent ? <GraduationCap size={40} /> : <Briefcase size={40} />}
          </div>
          <h2 className="text-6xl font-black leading-tight tracking-tighter">
            Portal <br/>
            <span className={isStudent ? 'text-indigo-400' : 'text-emerald-400'}>
              {isStudent ? 'Belajar Siswa' : 'Manajemen Guru'}
            </span>
          </h2>
          <p className="text-xl text-slate-400 font-medium italic">Informatika Cloud SMP Al Irsyad Surakarta.</p>
        </div>
      </div>

      <div className="flex-1 bg-white flex flex-col justify-center items-center px-8 py-12">
        <div className="w-full max-w-sm">
          <button onClick={onBack} className="flex items-center gap-2 text-slate-400 hover:text-slate-800 mb-12 font-bold group">
            <ArrowLeft size={18} className="group-hover:-translate-x-1 transition-transform" /> Kembali
          </button>

          <h3 className="text-4xl font-black text-slate-900 mb-2 tracking-tight">Masuk Ke Sistem</h3>
          <p className="text-slate-500 font-medium italic mb-10">Gunakan kredensial Cloud Anda.</p>

          {error.message && (
            <div className="mb-8 p-5 bg-rose-50 border border-rose-100 text-rose-600 rounded-2xl animate-in fade-in slide-in-from-top-2">
              <div className="flex items-start gap-3">
                <AlertCircle size={20} className="shrink-0 mt-0.5" />
                <p className="text-sm font-bold">{error.message}</p>
              </div>
            </div>
          )}

          {isEmptyDb && !isStudent && (
            <div className="mb-8 p-6 bg-amber-50 border border-amber-100 rounded-[2rem] space-y-4">
               <p className="text-xs text-amber-600 leading-relaxed font-medium">Belum ada akun Guru. Klik tombol untuk inisialisasi admin.</p>
               <button onClick={handleCreateInitialAdmin} disabled={isInitializing} className="w-full py-4 bg-amber-600 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-amber-700 disabled:opacity-50">
                 {isInitializing ? <RefreshCw className="animate-spin" size={16} /> : <ShieldCheck size={16} />} Inisialisasi Admin
               </button>
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Username</label>
              <div className="relative group">
                <UserIcon className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-indigo-500 transition-colors" size={20} />
                <input type="text" value={username} onChange={(e) => setUsername(e.target.value)} placeholder="Username" className="w-full pl-14 pr-6 py-5 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none focus:border-indigo-500 transition-all font-bold shadow-inner" required />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Password</label>
              <div className="relative group">
                <Lock className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300 group-focus-within:text-indigo-500 transition-colors" size={20} />
                <input type={showPassword ? 'text' : 'password'} value={password} onChange={(e) => setPassword(e.target.value)} placeholder="••••••••" className="w-full pl-14 pr-14 py-5 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none focus:border-indigo-500 transition-all font-bold shadow-inner" required />
                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400">
                  {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                </button>
              </div>
            </div>

            <button disabled={loading} className={`w-full py-5 text-white rounded-2xl font-black text-lg shadow-2xl transition-all disabled:opacity-50 active:scale-[0.98] ${isStudent ? 'bg-indigo-600 hover:bg-indigo-700' : 'bg-slate-900 hover:bg-emerald-600'}`}>
              {loading ? <Loader2 className="animate-spin mx-auto" size={24} /> : 'Login Sekarang'}
            </button>

            {isStudent && (
              <p className="text-center text-sm font-medium text-slate-400 mt-8">
                Belum terdaftar? <button type="button" onClick={onNavigateSignup} className="text-indigo-600 font-black hover:underline">Daftar</button>
              </p>
            )}

            <div className="pt-10 flex flex-col items-center gap-2">
               <div className="flex items-center gap-2 px-4 py-2 bg-slate-50 rounded-full">
                  <Database size={14} className="text-slate-400" />
                  <span className="text-[9px] font-black text-slate-400 uppercase">Informatika Cloud v2.1</span>
               </div>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useEffect } from 'react';
import { ArrowLeft, Loader2, Eye, EyeOff } from 'lucide-react';
import { User, ClassRoom } from '../types';
import { 
  auth, 
  firestore, 
  createUserWithEmailAndPassword, 
  doc, 
  setDoc, 
  getDocs, 
  collection,
  signOut
} from '../firebase.ts';
import { db } from '../App.tsx';

interface SignupProps {
  onBack: () => void;
  onSignup: () => void;
  logoUrl: string;
}

const Signup: React.FC<SignupProps> = ({ onBack, onSignup, logoUrl }) => {
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [classRoom, setClassRoom] = useState('');
  const [classes, setClasses] = useState<ClassRoom[]>([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const fetchClasses = async () => {
      try {
        const querySnapshot = await getDocs(collection(firestore, "elearning_classes_list"));
        setClasses(querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })) as ClassRoom[]);
      } catch (err) {
        console.error("Gagal memuat daftar kelas:", err);
      }
    };
    fetchClasses();
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    const email = `${username.trim().toLowerCase()}@alirsyad.sch.id`;

    try {
      const userCredential = await createUserWithEmailAndPassword(auth, email, password);
      const firebaseUser = userCredential.user;

      const userData: User = {
        id: firebaseUser.uid,
        name,
        username: username.toLowerCase(),
        classId: classRoom,
        role: 'STUDENT',
        status: 'PENDING',
        avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${username}`
      };

      // Simpan ke koleksi pusat 'users'
      await setDoc(doc(firestore, "users", firebaseUser.uid), userData);

      // Sinkronisasi: Simpan ke 'elearning_pending_students' untuk verifikasi Admin
      await db.append("elearning_pending_students", userData);

      alert("Pendaftaran berhasil! Tunggu konfirmasi Guru untuk mengaktifkan akun Anda.");
      await signOut(auth);
      onSignup();
    } catch (err: any) {
      alert("Pendaftaran Gagal: " + (err.message || "Pastikan username belum digunakan."));
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col justify-center items-center px-6 py-12 text-black font-['Plus_Jakarta_Sans']">
      <div className="w-full max-w-xl bg-white p-8 md:p-12 rounded-[2.5rem] shadow-2xl relative overflow-hidden">
        {loading && (
          <div className="absolute inset-0 bg-white/80 z-20 flex flex-col items-center justify-center">
            <Loader2 className="animate-spin text-emerald-600 mb-4" size={40} />
            <p className="text-xs font-black uppercase tracking-widest text-emerald-600">Memproses Cloud...</p>
          </div>
        )}

        <button onClick={onBack} className="flex items-center gap-2 text-slate-400 hover:text-slate-800 mb-8 font-bold transition-colors">
          <ArrowLeft size={18} /> Kembali ke Login
        </button>

        <div className="mb-10 text-center">
          <h3 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">Registrasi Cloud Siswa</h3>
          <p className="text-slate-400 text-sm italic font-medium">Buat akun belajar Informatika Anda.</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          {step === 1 ? (
            <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
              <div className="space-y-2">
                <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Nama Lengkap</label>
                <input 
                  value={name} 
                  onChange={e => setName(e.target.value)} 
                  className="w-full p-4 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none font-bold focus:border-emerald-500 transition-all shadow-inner" 
                  placeholder="Masukkan nama sesuai ijazah" 
                  required 
                />
              </div>
              <div className="space-y-2">
                <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Pilih Kelas</label>
                <select 
                  value={classRoom} 
                  onChange={e => setClassRoom(e.target.value)} 
                  className="w-full p-4 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none font-bold focus:border-emerald-500 transition-all shadow-inner appearance-none" 
                  required
                >
                  <option value="">-- Pilih Kelas --</option>
                  {classes.map(c => <option key={c.id} value={c.name}>Kelas {c.name}</option>)}
                </select>
              </div>
              <button 
                type="button" 
                onClick={() => { if(name && classRoom) setStep(2); else alert('Lengkapi Nama dan Kelas!'); }} 
                className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black text-lg shadow-xl hover:bg-emerald-600 active:scale-[0.98] transition-all"
              >
                Lanjut Langkah 2
              </button>
            </div>
          ) : (
            <div className="space-y-6 animate-in slide-in-from-right-4 duration-300">
              <div className="space-y-2">
                <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Username Baru</label>
                <input 
                  value={username} 
                  onChange={e => setUsername(e.target.value.toLowerCase().replace(/\s/g, ''))} 
                  className="w-full p-4 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none font-bold focus:border-emerald-500 transition-all shadow-inner" 
                  placeholder="Contoh: ahmad_8a" 
                  required 
                />
                <p className="text-[9px] text-slate-400 font-medium ml-1">Username ini akan digunakan untuk login.</p>
              </div>
              <div className="space-y-2">
                <label className="block text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Password Baru</label>
                <div className="relative">
                  <input 
                    type={showPassword ? 'text' : 'password'} 
                    value={password} 
                    onChange={e => setPassword(e.target.value)} 
                    className="w-full p-4 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none font-bold focus:border-emerald-500 transition-all shadow-inner" 
                    placeholder="Min. 6 karakter" 
                    required 
                  />
                  <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 hover:text-emerald-500 transition-colors">
                    {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                  </button>
                </div>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setStep(1)} className="flex-1 py-4 bg-slate-50 text-slate-500 rounded-2xl font-bold hover:bg-slate-100 transition-all">Kembali</button>
                <button type="submit" className="flex-[2] py-4 bg-emerald-600 text-white rounded-2xl font-black shadow-xl hover:bg-slate-900 active:scale-[0.98] transition-all">Daftar Sekarang</button>
              </div>
            </div>
          )}
        </form>
      </div>
    </div>
  );
};

export default Signup;
